#######################################################################################
#
# This module encapsulates functions that may be used to calculate
# the slope and r2 (fit) of a trendline
# of a Zipf distribution (byRank or bySize).
#
# The byRank distribution plots the values (y-axis)
# against the ranks of the values from largest to smallest
# (x-axis) in log-log scale. The ranks are generated automatically.
#
# The bySize distribution plots the values (y-axis)
# against the supplied keys (x-axis) in log-log scale.
#
# Usage: Call bySize(sizes, counts) and/or byRank(counts) functions
# Output: slope and R2
#
# WARNING:  If an error occurs the current code will NOT raise an exception;
#           it will only print an error message (for ShedSkin compatibility).
#           This may cause problems, if the error messages go undetected
#           (e.g., this code is run in batch mode).
#
# Authors: Chris Wagner and Bill Manaris (based on VB code by Chuck McCormick and Bill Manaris)
#

from utilities import *    # mapValue, etc.
from PythonMusic.nevmuse import *   # Zipf Metrics
from math import log, sqrt             # logarithmic calculations


def byRank(counts):
   """Measure the Zipf slope of a set of counts, ranked from largest to smallest.

   Ranks the counts from largest to smallest, then fits a trendline to the rank-against-
   count plot on a log-log scale. A slope close to -1 with a good fit indicates a Zipf-like
   distribution.

   Args:
       counts (Iterable[int or float]): How often each item occurs.

   Returns:
       slope (float): The slope of the fitted trendline.
       r2 (float): How well the trendline fits the data, from 0.0 to 1.0.
       yint (float): The trendline's y-intercept.
   """
   # ensure counts is indexable (support Python 3 dict_values)
   counts = list(counts)

   newCounts = []   # to hold the deep copy
   newRanks = []    # the newly created ranks
   numberOfCounts = len(counts)
   for index in range(numberOfCounts):
      newCounts.append(counts[index])         # deep copy the counts
      newRanks.append(numberOfCounts - index)    # create the ranks: highest frequency has smallest rank

   newCounts.sort()

   checkRanksAndCounts(newRanks, newCounts)
   slope, r2, yint = getSlopeR2(newRanks, newCounts)
   
   return slope, r2, yint


def bySize(sizes, counts):
   """Measure the Zipf slope of a set of counts plotted against given sizes.

   Like byRank(), but plots the counts against the sizes you supply rather than against
   automatic ranks, on a log-log scale, then fits a trendline.

   Args:
       sizes (Iterable[int or float]): The size (the x value) for each count.
       counts (Iterable[int or float]): How often each item occurs.

   Returns:
       slope (float): The slope of the fitted trendline.
       r2 (float): How well the trendline fits the data, from 0.0 to 1.0.
       yint (float): The trendline's y-intercept.
   """
   # ensure sizes and counts are indexable (support Python 3 dict_keys/values)
   sizes = list(sizes)
   counts = list(counts)

   checkRanksAndCounts(sizes, counts)
   slope, r2, yint = getSlopeR2(sizes, counts)

   return slope, r2, yint


######################################
######### SUPPORTING METHODS #########
######################################

def checkRanksAndCounts(ranks, counts):
   """Check that ranks and counts are valid for a Zipf measurement.

   Confirms that both lists hold at least one item, are the same length, and contain no
   zero or negative values. On bad input, prints an error rather than raising.

   Args:
       ranks (list[int or float]): The rank (the x value) for each count.
       counts (list[int or float]): How often each item occurs.
   """
   if len(counts) == 0:
      raise ValueError('Counts should contain at least one element')
   if min(counts) <= 0.0:
      raise ValueError('Counts should be strictly positive: %f' % (min(counts)))
   if len(ranks) == 0:
      raise ValueError('Ranks should contain at least one element')
   if min(ranks) <= 0.0:
      raise ValueError('Ranks should be strictly positive: %f' % (min(ranks)))
   if len(ranks) != len(counts):
      raise ValueError('Ranks (length: %d) and counts (length: %d) should have the same size.' % (len(ranks), len(counts)))


def getSlopeR2(ranks, counts):
   """Fit a Zipf trendline to a set of ranks and counts.

   Fits a trendline to the rank-against-count plot on a log-log scale and returns its
   slope, fit, and y-intercept. If the slope or fit cannot be worked out, zero is returned
   for it. Two special cases: a single repeated value (a vertical trendline) gives a slope
   and fit of 0; a perfectly even spread (a horizontal trendline) gives a slope of 0 and a
   fit of 1.

   Args:
       ranks (list[int or float]): The rank (the x value) for each count.
       counts (list[int or float]): How often each item occurs.

   Returns:
       slope (float): The slope of the fitted trendline.
       r2 (float): How well the trendline fits the data, from 0.0 to 1.0.
       yint (float): The trendline's y-intercept.
   """
   assert len(ranks) == len(counts), 'Ranks and counts must have the same length.'

   sumX = sumY = sumXY = sumX2 = sumY2 = slope = r2 = 0.0

   numberOfRanks = len(ranks)

   # one exterme case:
   # if the phenomenon is monotonous (only one type of event, e.g., ['a', 'a', 'a']),
   # then the slope is negative infinity (cannot draw a line with only one data point),
   # so indicate this with slope = 0 AND r2 = 0
   if numberOfRanks == 1:
      slope = 0.0
      r2 = 0.0

   else:
      # the other extreme case:
      # if the phenomenon is uniformly distributed (several types of events,
      # but all having the same number of instances, e.g., ['a', 'b', 'a', 'b', 'a', 'b']),
      # then the slope = 0 and r2 = 1 (a horizontal line).

      # check if all counts are equal
      i = 0
      allCountsEqual = True   # assume they are all equal
      while allCountsEqual and i < numberOfRanks-1:
         allCountsEqual = (counts[i] == counts[i + 1])   # update hypothesis
         i = i + 1

      if allCountsEqual:  # is phenomenon uniformly distributed?
         slope = 0.0
         r2 = 1.0

      # general case, so calculate actual slope and r2 values
      else:

         # Sum up the values for the calculations
         for index in range(numberOfRanks):
            sumX += log(ranks[index],10)
            sumY += log(counts[index],10)
            sumXY += log(ranks[index],10) * log(counts[index],10)
            sumX2 += log(ranks[index],10)**2
            sumY2 += log(counts[index],10)**2

            # calculate the slope
            if ((numberOfRanks * sumX2 - sumX * sumX) == 0.0):
               slope = 0.0
            else:
                slope = ((numberOfRanks * sumXY - sumX * sumY) / (numberOfRanks * sumX2 - sumX * sumX))

            # calculate the r2
            if(sqrt((numberOfRanks * sumX2 - sumX * sumX) * (numberOfRanks * sumY2 - sumY * sumY)) == 0.0):
               r2 = 0.0
            else:
               r = (numberOfRanks * sumXY - sumX * sumY) / sqrt((numberOfRanks * sumX2 - sumX * sumX) * (numberOfRanks * sumY2 - sumY * sumY))
               r2 = r * r

   # calulate y-intercept
   yint = (sumY - slope * sumX) / len(ranks)

   return slope, r2, yint


def measureScore(scores, metrics, quantum=0.25):
   """Measure a list of scores against a list of Zipf metrics.

   Runs every metric on every score and collects the results.

   Args:
       scores (list[Score]): The scores to measure.
       metrics (list[Metric]): The Zipf metrics to apply.
       quantum (float, optional): The rhythmic grid to measure on, in beats, where 0.25 is a sixteenth note.

   Returns:
       allMeasurements (list[list]): One row per score. Each row holds the score's measurement for each metric, followed by the score's title.
   """
   from PythonMusic.nevmuse.Surveyor import Surveyor

   # scores must be a list
   if not isinstance(scores, list):
      raise TypeError("scores must be a list of Score objects")

   allMeasurements = []
   for score in scores:
      # run each Metric on this Score
      surveyor = Surveyor()
      surveyor.survey(score, metrics, quantum)

      # get measurement from each Metric
      measurements = [metric.getMeasurement() for metric in metrics]

      # append title as last element
      measurements.append(score.getTitle())
      allMeasurements.append(measurements)
   # now, allMeasurements contains a list of lists
   # each inner list contains [Measurement1, Measurement2, ..., filename]

   return allMeasurements


def measureMidi(files, metrics, quantum=0.25):
   """Measure a list of MIDI files against a list of Zipf metrics.

   Reads each MIDI file into a score, then measures the scores like measureScore().

   Args:
       files (list[str]): The paths of the MIDI files to measure.
       metrics (list[Metric]): The Zipf metrics to apply.
       quantum (float, optional): The rhythmic grid to measure on, in beats, where 0.25 is a sixteenth note.

   Returns:
       allMeasurements (list[list]): One row per file. Each row holds the file's measurement for each metric, followed by the score's title.
   """
   from music import Score, Read

   # files must be a list
   if not isinstance(files, list):
      raise TypeError("files must be a list of strings")

   scores = []
   for filePath in files:
      # read MIDI file into a Score
      score = Score()
      Read.midi(score, filePath)

      # add score to list
      scores.append(score)

   # pass list of scores to measureScore
   allMeasurements = measureScore(scores, metrics, quantum)
   return allMeasurements


def measureDataByRank(datasets, metricName='ByRank'):
   """Measure a list of count datasets by rank.

   Runs byRank() on each dataset and wraps the result as a measurement.

   Args:
       datasets (list[list[int or float]]): The datasets to measure. Each dataset is a list of counts.
       metricName (str, optional): A name to label the measurements with.

   Returns:
       allMeasurements (list[list]): One row per dataset, each holding that dataset's measurement.
   """
   # validate datasets is a list
   if not isinstance(datasets, list):
      raise TypeError("datasets must be a list")

   if len(datasets) == 0:
      raise TypeError("datasets must be a non-empty list")

   allMeasurements = []

   for counts in datasets:
      # call byRank to get slope, r2, yint
      slope, r2, yint = byRank(counts)

      # create SimpleMeasurement object
      measurement = _SimpleMeasurement(metricName, slope, r2, yint)

      # append [measurement] to results
      allMeasurements.append([measurement])

   return allMeasurements


def measureDataBySize(datasets, metricName='BySize'):
   """Measure a list of size-and-count datasets.

   Runs bySize() on each dataset and wraps the result as a measurement.

   Args:
       datasets (list[list[list[int or float]]]): The datasets to measure. Each dataset is a [sizes, counts] pair of parallel lists.
       metricName (str, optional): A name to label the measurements with.

   Returns:
       allMeasurements (list[list]): One row per dataset, each holding that dataset's measurement.
   """
   # validate datasets is a list
   if not isinstance(datasets, list):
      raise TypeError("datasets must be a list")

   if len(datasets) == 0:
      raise TypeError("datasets must be a non-empty list")

   allMeasurements = []

   for dataset in datasets:
      # unpack each dataset
      try:
         sizes, counts = dataset
      except (ValueError, TypeError):
         raise TypeError("each dataset must be a list [sizes, counts]")

      # call bySize to get slope, r2, yint
      slope, r2, yint = bySize(sizes, counts)

      # create SimpleMeasurement object
      measurement = _SimpleMeasurement(metricName, slope, r2, yint)

      # append [measurement] to results
      allMeasurements.append([measurement])

   return allMeasurements


def writeCSV(measurements, filename):
   """Write measurements to a CSV file.

   Takes the measurements returned by measureScore() or measureMidi() and writes them to a
   spreadsheet file, one row per score.

   Args:
       measurements (list[list]): The measurements to write, as returned by measureScore() or measureMidi().
       filename (str): The CSV file to write.
   """
   import os
   import unicodedata
   from PythonMusic.nevmuse.data.Measurement import Measurement

   # measurements must be a list of lists
   if not measurements:
      raise ValueError("measurements cannot be empty")

   if not isinstance(measurements[0], (list, tuple)):
      raise TypeError("measurements must be a list of lists (from measureMidi/measureScore)")

   # check if the last element is a label (string) or a Measurement object
   # to determine if we have source names
   lastElement = measurements[0][-1]
   hasSourceNames = isinstance(lastElement, str)

   # extract measurements and optional names
   measurementsList = []
   names = []
   if hasSourceNames:
      for measurementRow in measurements:
         # last element is the name/label, everything else is Measurement objects
         measurementsList.append(measurementRow[:-1])
         names.append(measurementRow[-1])
   else:
      # all elements are Measurement objects
      for measurementRow in measurements:
         measurementsList.append(measurementRow)

   # helper function to convert to ASCII (from advMetricRunner.jythonSurvey.py)
   def convertToASCII(string):
      # convert input to unicode string
      unicodeString = str(string)

      # convert string to NFKD format (separate characters from accents - creates two characters from one)
      nfkdString = unicodedata.normalize('NFKD', unicodeString)

      # re-encode to ASCII - ignore non-ASCII characters (like accents or symbols)
      asciiBytes = nfkdString.encode('ascii', 'ignore')
      asciiString = asciiBytes.decode('ascii')
      asciiString = asciiString.replace(",", "")

      # return ASCII-only version of the string
      return asciiString

   # write CSV file
   with open(filename, mode="w") as csvfile:
      # write headers from first measurement set
      firstMeasurements = measurementsList[0]
      for measurement in firstMeasurements:
         keys = measurement.keysToArray()
         for key in keys:
            csvfile.write(key + ",")

      # add final headers (SourceName and/or Index columns)
      if hasSourceNames:
         csvfile.write("SourceName,")
      csvfile.write("Index")   # no trailing comma, no newline yet

      # write data rows
      for i, measurements in enumerate(measurementsList):
         csvfile.write("\n")   # start each data row with newline

         # write all measurement values
         for measurement in measurements:
            values = measurement.valuesToArray()
            for value in values:
               csvfile.write(convertToASCII(value) + ",")

         # write source name if present
         if hasSourceNames:
            sourceName = names[i]
            if os.path.sep in sourceName:
               sourceName = os.path.basename(sourceName)
            sourceName = convertToASCII(sourceName)
            csvfile.write(sourceName + ",")

         # write index (1-based, last column, no trailing comma or newline)
         index = i + 1
         csvfile.write(convertToASCII(index))


class _SimpleMeasurement:
   """"""

   def __init__(self, metricName, slope, r2, yint):
      self.metricName = metricName
      self.slope = slope
      self.r2 = r2
      self.yint = yint

   def keysToArray(self):
      """"""
      return [f"{self.metricName}_Slope", f"{self.metricName}_R2", f"{self.metricName}_YInt"]

   def valuesToArray(self):
      """"""
      return [self.slope, self.r2, self.yint]

